                { get: (key: string) => (key === 'status' ? 'dismissed' : 'value'), delete: jest.fn().mockResolvedValue(undefined) },
                { get: (key: string) => (key === 'status' ? 'active' : 'value'), delete: jest.fn().mockResolvedValue(undefined) },
