describe('importBokResidentsFromExcel (new feature tests)', () => {
    const mockSettings2: Settings = {
        id: 'global-settings',
        coordinators: [
            { uid: 'coord-1', name: 'Jan Kowalski', isAdmin: false, departments: ['IT', 'HR'], visibilityMode: 'department' },
