            'Imię': 'Jan', 'Nazwisko': 'Kierowca', 'Rola': 'Kierowca',
            'Koordynator': 'Jan Kowalski', 'Data zameldowania': '01.01.2024',
            'Miejscowość': 'Warszawa', 'Adres': 'Testowa 1', 'Pokój': '101',
            'Narodowość': 'Polska', 'Zakład': 'Transport',
