// ─── 5. Sub-tab filtering logic (pure JS) ────────────────────────────────────

describe('BOK sub-tab filtering logic', () => {
    const makeResident = (overrides: Partial<BokResident>): BokResident => ({
        id: 'r1',
        firstName: 'Jan',
        lastName: 'Test',
        fullName: 'Test Jan',
        role: 'Kierowca',
        coordinatorId: 'coord-1',
        nationality: 'Polska',
        address: '',
        roomNumber: '',
        zaklad: '',
        gender: 'Mężczyzna',
        checkInDate: '2024-01-01',
        checkOutDate: null,
        sendDate: null,
        dismissDate: null,
        returnStatus: '',
        status: 'active',
        comments: '',
        ...overrides,
    });

    // Replicate the filtering logic from entity-view.tsx
    const isAktywny = (r: BokResident) =>
        r.status !== 'dismissed' && !r.dismissDate && !r.checkOutDate;

    const isWyslany = (r: BokResident) =>
        r.status !== 'dismissed' && !r.dismissDate && !!r.checkOutDate;

    const isZwolniony = (r: BokResident) =>
        r.status === 'dismissed' || !!r.dismissDate;

    it('active resident with no dates → Aktywni', () => {
        const r = makeResident({});
        expect(isAktywny(r)).toBe(true);
        expect(isWyslany(r)).toBe(false);
        expect(isZwolniony(r)).toBe(false);
    });

    it('resident with checkOutDate and status active → Wyslani', () => {
        const r = makeResident({ checkOutDate: '2026-02-01' });
        expect(isAktywny(r)).toBe(false);
        expect(isWyslany(r)).toBe(true);
        expect(isZwolniony(r)).toBe(false);
    });

    it('resident with checkOutDate AND dismissDate → Zwolnieni (not Wyslani)', () => {
        const r = makeResident({ checkOutDate: '2026-02-01', dismissDate: '2026-03-01' });
        expect(isAktywny(r)).toBe(false);
        expect(isWyslany(r)).toBe(false);
        expect(isZwolniony(r)).toBe(true);
    });

    it('resident with status=dismissed → Zwolnieni', () => {
        const r = makeResident({ status: 'dismissed' });
        expect(isAktywny(r)).toBe(false);
        expect(isWyslany(r)).toBe(false);
        expect(isZwolniony(r)).toBe(true);
    });

    it('resident with dismissDate set (past date) → Zwolnieni', () => {
        const r = makeResident({ dismissDate: '2026-01-01' });
        expect(isAktywny(r)).toBe(false);
        expect(isWyslany(r)).toBe(false);
        expect(isZwolniony(r)).toBe(true);
    });

    it('dismissed resident with checkOutDate → Zwolnieni (not Wyslani)', () => {
        const r = makeResident({ status: 'dismissed', checkOutDate: '2026-02-01' });
        expect(isWyslany(r)).toBe(false);
        expect(isZwolniony(r)).toBe(true);
    });

    it('each resident appears in exactly ONE sub-tab', () => {
        const residents = [
            makeResident({}),
            makeResident({ checkOutDate: '2026-02-01' }),
            makeResident({ dismissDate: '2026-01-01' }),
            makeResident({ status: 'dismissed' }),
            makeResident({ checkOutDate: '2026-02-01', dismissDate: '2026-03-01' }),
        ];

        for (const r of residents) {
            const tabs = [isAktywny(r), isWyslany(r), isZwolniony(r)];
            const trueCount = tabs.filter(Boolean).length;
            expect(trueCount).toBe(1);
        }
    });
});

"use client";

import { Suspense, useState, useEffect } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { Button } from "@/components/ui/button";
import {
    Card,
    CardContent,
    CardDescription,
    CardFooter,
    CardHeader,
    CardTitle,
} from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { login } from '@/lib/auth';
import { Download, Loader2, Eye, EyeOff } from 'lucide-react';
import { usePWAInstaller } from '@/components/pwa-installer';

const ModernHouseIcon = (props: React.SVGProps<SVGSVGElement>) => (
    <svg
        xmlns="http://www.w3.org/2000/svg"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
        {...props}
    >
        <path d="M3 9l9-7 9 7v11a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z"></path>
        <polyline points="9 22 9 12 15 12 15 22"></polyline>
    </svg>
);

function LoginForm() {
    const router = useRouter();
    const { toast } = useToast();
    const { installPrompt, handleInstallClick } = usePWAInstaller();
    const [name, setName] = useState('');
    const [password, setPassword] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [isLoading, setIsLoading] = useState(false);

    const searchParams = useSearchParams();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsLoading(true);

        // Check for callbackUrl to redirect back to the original page (e.g. from push notification)
        // Only allow relative paths to prevent open redirect attacks
        const rawCallbackUrl = searchParams.get('callbackUrl') || '';
        const callbackUrl = rawCallbackUrl.startsWith('/') && !rawCallbackUrl.startsWith('//')
            ? rawCallbackUrl
            : '/dashboard?view=dashboard';

        try {
            const { success, user } = await login(name, password);
            if (success && user) {
                toast({
                    title: `Witaj z powrotem, ${user.name}!`,
                    duration: 2000,
                });
                router.push(callbackUrl);
            } else {
                toast({
                    variant: "destructive",
                    title: "Błąd logowania",
                    description: "Nieprawidłowy login lub hasło."
                });
            }
        } catch (error) {
            toast({
                variant: "destructive",
                title: "Wystąpił błąd",
                description: "Spróbuj ponownie później."
            });
        } finally {
            setIsLoading(false);
        }
    };

    return (
        <form onSubmit={handleLogin}>
            <CardContent className="grid gap-4 animate-fade-in-up" style={{ animationDelay: '0.2s' }}>
                <div className="grid gap-2 text-left">
                    <Label htmlFor="name">Imię i nazwisko / Login</Label>
                    <Input
                        id="name"
                        type="text"
                        placeholder="np. admin lub Jan Kowalski"
                        value={name}
                        onChange={(e) => setName(e.target.value)}
                        required
                        disabled={isLoading}
                    />
                </div>
                <div className="grid gap-2 text-left">
                    <Label htmlFor="password">Hasło</Label>
                    <div className="relative">
                        <Input
                            id="password"
                            type={showPassword ? "text" : "password"}
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            required
                            disabled={isLoading}
                            className="pr-10"
                        />
                        <button
                            type="button"
                            onClick={() => setShowPassword(v => !v)}
                            className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground"
                            tabIndex={-1}
                        >
                            {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
                        </button>
                    </div>
                </div>
            </CardContent>
            <CardFooter className="flex-col gap-4 animate-fade-in-up" style={{ animationDelay: '0.4s' }}>
                <Button className="w-full" type="submit" disabled={isLoading || password === ''}>
                    {isLoading ? <Loader2 className="animate-spin" /> : "Zaloguj się"}
                </Button>
                {installPrompt && (
                    <Button variant="outline" className="w-full" onClick={handleInstallClick}>
                        <Download className="mr-2 h-4 w-4" />
                        Zainstaluj aplikację
                    </Button>
                )}
            </CardFooter>
        </form>
    );
}

export default function LoginPage() {
    return (
        <div className="relative flex h-screen w-full items-center justify-center bg-muted/40 px-4 overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-full z-0">
                <div className="absolute top-1/4 left-1/4 w-72 h-72 bg-primary/20 rounded-full mix-blend-multiply filter blur-xl opacity-70 animate-blob"></div>
                <div className="absolute top-1/2 right-1/4 w-72 h-72 bg-accent/20 rounded-full mix-blend-multiply filter blur-xl opacity-70 animate-blob animation-delay-2000"></div>
                <div className="absolute bottom-1/4 left-1/2 w-72 h-72 bg-secondary/20 rounded-full mix-blend-multiply filter blur-xl opacity-70 animate-blob animation-delay-4000"></div>
            </div>
            <Card className="w-full max-w-sm z-10 animate-scale-in">
                <CardHeader className="items-center text-center animate-fade-in-up">
                    <ModernHouseIcon className="h-8 w-8 text-primary" />
                    <CardTitle>Witaj w SmartHouse</CardTitle>
                    <CardDescription>Zaloguj się, aby kontynuować</CardDescription>
                </CardHeader>
                <Suspense fallback={<div className="h-48 flex items-center justify-center text-muted-foreground">Ładowanie formularza...</div>}>
                    <LoginForm />
                </Suspense>
            </Card>
        </div>
    );
}

