"use client";

import React, { useEffect, useState, useMemo, useRef } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogFooter,
  DialogDescription,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from '@/components/ui/form';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { ScrollArea } from '@/components/ui/scroll-area';
import type { NonEmployee, Settings, SessionData } from '@/types';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { CalendarIcon, X, Loader2, Eye } from 'lucide-react';
import { Calendar } from '@/components/ui/calendar';
import { format, parse, isValid, parseISO } from 'date-fns';
import { Combobox } from './ui/combobox';
import { useToast } from '@/hooks/use-toast';
import { useMainLayout } from './main-layout';
import { AddressPreviewDialog } from '@/components/address-preview-dialog';

const formSchema = z.object({
  firstName: z.string().min(1, "Imię jest wymagane."),
  lastName: z.string().min(1, "Nazwisko jest wymagane."),
  coordinatorId: z.string().min(1, "Koordynator jest wymagany."),
  locality: z.string().min(1, 'Miejscowość jest wymagana.'),
  address: z.string().min(1, 'Adres jest wymagany.'),
  roomNumber: z.string().min(1, 'Pokój jest wymagany.'),
  nationality: z.string().min(1, "Narodowość jest wymagana."),
  gender: z.string().min(1, "Płeć jest wymagana."),
  checkInDate: z.date({ required_error: "Data zameldowania jest wymagana.", invalid_type_error: "Data zameldowania jest wymagana." }),
  checkOutDate: z.date().nullable().optional(),
  departureReportDate: z.date().nullable().optional(),
  comments: z.string().optional(),
  paymentType: z.string().nullable().optional(),
  paymentAmount: z.number().nullable().optional(),
});

type NonEmployeeFormData = Omit<z.infer<typeof formSchema>, 'checkInDate' | 'checkOutDate' | 'locality' | 'departureReportDate'> & {
  checkInDate: string | null;
  checkOutDate?: string | null;
  departureReportDate?: string | null;
};

const parseDate = (dateString: string | null | undefined): Date | null => {
  if (!dateString) return null;
  const date = parseISO(dateString);
  return isValid(date) ? date : null;
};

const DateInput = ({
  value,
  onChange,
  disabled,
  id,
}: {
  value?: Date | null;
  onChange: (date?: Date | null) => void;
  disabled?: (date: Date) => boolean;
  id?: string;
}) => {
  const [inputValue, setInputValue] = useState('');
  const [isPopoverOpen, setIsPopoverOpen] = useState(false);

  useEffect(() => {
    if (value) {
      setInputValue(format(value, 'yyyy-MM-dd'));
    } else {
      setInputValue('');
    }
  }, [value]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setInputValue(e.target.value);
    const parsedDate = parse(e.target.value, 'yyyy-MM-dd', new Date());
    if (!isNaN(parsedDate.getTime())) {
      onChange(parsedDate);
    }
  };

  const handleDateSelect = (date?: Date | null) => {
    if (date) {
      onChange(date);
      setInputValue(format(date, 'yyyy-MM-dd'));
      setIsPopoverOpen(false);
    } else {
      onChange(null);
      setInputValue('');
    }
  };

  const handleClear = (e: React.MouseEvent) => {
    e.stopPropagation();
    handleDateSelect(null);
  }

  return (
    <Popover open={isPopoverOpen} onOpenChange={setIsPopoverOpen}>
      <PopoverTrigger asChild>
        <div className="relative">
          <Input
            id={id}
            type="text"
            value={inputValue}
            onChange={handleInputChange}
            placeholder="rrrr-mm-dd"
            className="pr-10"
          />
          <div className="absolute right-3 top-1/2 -translate-y-1/2 h-4 w-4 flex items-center">
            {value ? (
              <X className="h-4 w-4 text-muted-foreground hover:text-foreground cursor-pointer" onClick={handleClear} />
            ) : (
              <CalendarIcon className="h-4 w-4 text-muted-foreground" />
            )}
          </div>
        </div>
      </PopoverTrigger>
      <PopoverContent className="w-auto p-0" align="start">
        <Calendar
          mode="single"
          selected={value || undefined}
          onSelect={d => handleDateSelect(d)}
          disabled={disabled}
          initialFocus
        />
      </PopoverContent>
    </Popover>
  );
};

export function AddNonEmployeeForm({
  isOpen,
  onOpenChange,
  onSave,
  settings,
  nonEmployee,
  currentUser,
}: {
  isOpen: boolean;
  onOpenChange: (isOpen: boolean) => void;
  onSave: (data: NonEmployeeFormData) => void;
  settings: Settings;
  nonEmployee: NonEmployee | null;
  currentUser: SessionData;
}) {
  const { toast } = useToast();
  const { handleDismissNonEmployee, allEmployees, allNonEmployees, allBokResidents } = useMainLayout();
  const [isDismissing, setIsDismissing] = useState(false);
  const [isAddressPreviewOpen, setIsAddressPreviewOpen] = useState(false);

  const form = useForm<z.infer<typeof formSchema>>({
    resolver: zodResolver(formSchema),
    defaultValues: {
      firstName: '',
      lastName: '',
      coordinatorId: '',
      locality: '',
      address: '',
      roomNumber: '',
      nationality: '',
      gender: '',
      checkInDate: undefined,
      checkOutDate: null,
      departureReportDate: null,
      comments: '',
      paymentType: null,
      paymentAmount: null,
    },
  });

  const selectedCoordinatorId = form.watch('coordinatorId');
  const selectedLocality = form.watch('locality');
  const selectedAddress = form.watch('address');

  const coordinatorOptions = useMemo(() => {
    return settings.coordinators
      .map(c => ({ value: c.uid, label: c.name }))
      .sort((a, b) => a.label.localeCompare(b.label));
  }, [settings.coordinators]);

  const nationalityOptions = useMemo(() =>
    settings.nationalities.map(n => ({ value: n, label: n })).sort((a, b) => a.label.localeCompare(b.label)),
    [settings.nationalities]);

  const genderOptions = useMemo(() =>
    settings.genders.sort((a, b) => a.localeCompare(b)),
    [settings.genders]);

  const paymentTypesNZOptions = useMemo(() =>
    settings.paymentTypesNZ.filter(Boolean).map(p => ({ value: p, label: p })).sort((a, b) => a.label.localeCompare(b.label)),
    [settings.paymentTypesNZ]);

  const availableLocalities = useMemo(() => {
    if (!settings) return [];
    let userAddresses = settings.addresses;
    if (selectedCoordinatorId) {
      userAddresses = settings.addresses.filter(a => a.coordinatorIds.includes(selectedCoordinatorId));
    } else if (!currentUser.isAdmin) {
      userAddresses = settings.addresses.filter(a => a.coordinatorIds.includes(currentUser.uid));
    }

    const localities = [...new Set(userAddresses.map(a => a.locality))];
    return localities.sort((a, b) => a.localeCompare(b));
  }, [settings, currentUser, selectedCoordinatorId]);

  const availableAddresses = useMemo(() => {
    if (!settings) return [];
    let userAddresses = settings.addresses;
    if (selectedCoordinatorId) {
      userAddresses = settings.addresses.filter(a => a.coordinatorIds.includes(selectedCoordinatorId));
    } else if (!currentUser.isAdmin) {
      userAddresses = settings.addresses.filter(a => a.coordinatorIds.includes(currentUser.uid));
    }

    if (!selectedLocality) return userAddresses;

    const filtered = userAddresses.filter(a => a.locality === selectedLocality);
    return [...filtered].sort((a, b) => a.name.localeCompare(b.name));
  }, [settings, selectedLocality, currentUser, selectedCoordinatorId]);

  const availableRoomsWithCapacity = useMemo(() => {
    const rooms = settings.addresses.find(a => a.name === selectedAddress)?.rooms || [];
    return [...rooms].sort((a, b) => a.name.localeCompare(b.name, undefined, { numeric: true })).map(room => {
      let occupied = 0;

      if (allEmployees) {
        occupied += allEmployees.filter(e => e.status === 'active' && e.address === selectedAddress && String(e.roomNumber) === room.name).length;
      }
      if (allNonEmployees) {
        occupied += allNonEmployees.filter(e => e.status === 'active' && e.address === selectedAddress && String(e.roomNumber) === room.name).length;
      }
      if (allBokResidents) {
        occupied += allBokResidents.filter(e => (e.status === 'active' || !e.status || e.status === '') && e.address === selectedAddress && String(e.roomNumber) === room.name).length;
      }

      return {
        ...room,
        occupied,
        available: Math.max(0, room.capacity - occupied)
      };
    });
  }, [settings.addresses, selectedAddress, allEmployees, allNonEmployees, allBokResidents]);

  useEffect(() => {
    if (nonEmployee) {
      const neAddress = settings.addresses.find(a => a.name === nonEmployee.address);
      const neLocality = neAddress ? neAddress.locality : '';
      form.reset({
        ...nonEmployee,
        locality: neLocality,
        checkInDate: parseDate(nonEmployee.checkInDate) || undefined,
        checkOutDate: parseDate(nonEmployee.checkOutDate),
        departureReportDate: parseDate(nonEmployee.departureReportDate),
        paymentType: nonEmployee.paymentType ?? null,
        paymentAmount: nonEmployee.paymentAmount ?? null,
        comments: nonEmployee.comments ?? '',
      });
    } else {
      form.reset({
        firstName: '',
        lastName: '',
        coordinatorId: currentUser.isAdmin ? '' : currentUser.uid,
        locality: '',
        address: '',
        roomNumber: '',
        nationality: '',
        gender: '',
        checkInDate: new Date(),
        checkOutDate: null,
        departureReportDate: null,
        comments: '',
        paymentType: null,
        paymentAmount: null,
      });
    }
  }, [nonEmployee, isOpen, form, settings.addresses, currentUser]);

  const onSubmit = async (values: z.infer<typeof formSchema>) => {
    const formatDate = (date: Date | null | undefined): string | null => {
      if (!date) return null;
      return format(date, 'yyyy-MM-dd');
    }

    // eslint-disable-next-line @typescript-eslint/no-unused-vars
    const { locality, ...restOfValues } = values;

    const formData: NonEmployeeFormData = {
      ...restOfValues,
      checkInDate: formatDate(values.checkInDate),
      checkOutDate: formatDate(values.checkOutDate),
      departureReportDate: formatDate(values.departureReportDate),
      paymentAmount: values.paymentAmount ?? null,
    };

    try {
      await onSave(formData);
      onOpenChange(false);
    } catch (e) {
      console.error('Form submission failed:', e);
    }
  };

  const handleCoordinatorChange = (value: string) => {
    form.setValue('coordinatorId', value);
    form.setValue('locality', '');
    form.setValue('address', '');
    form.setValue('roomNumber', '');
  }

  const handleLocalityChange = (value: string) => {
    form.setValue('locality', value);
    form.setValue('address', '');
    form.setValue('roomNumber', '');
  }

  const handleAddressChange = (value: string) => {
    form.setValue('address', value);
    form.setValue('roomNumber', '');
  }

  const handleDismissClick = async () => {
    if (!nonEmployee || isDismissing) return;

    const checkOutDate = form.getValues('checkOutDate');

    // Validate type and existence
    if (!checkOutDate || !(checkOutDate instanceof Date) || !isValid(checkOutDate)) {
      form.setError('checkOutDate', {
        type: 'manual',
        message: 'Data wymeldowania jest wymagana i musi być poprawna, aby zwolnić mieszkańca.',
      });
      return;
    }



    setIsDismissing(true);
    try {
      const values = form.getValues();
      const formatDateFn = (date: Date | null | undefined): string | null => {
        if (!date) return null;
        return format(date, 'yyyy-MM-dd');
      }
      // eslint-disable-next-line @typescript-eslint/no-unused-vars
      const { locality, ...restOfValues } = values;
      const formData: NonEmployeeFormData = {
        ...restOfValues,
        checkInDate: formatDateFn(values.checkInDate),
        checkOutDate: formatDateFn(values.checkOutDate),
        departureReportDate: formatDateFn(values.departureReportDate),
      };
      await onSave(formData);
      await handleDismissNonEmployee(nonEmployee.id, checkOutDate);
      onOpenChange(false);
    } catch (e) {
      console.error('Dismiss failed:', e);
    } finally {
      setIsDismissing(false);
    }
  };

  return (
    <>
      <Dialog open={isOpen} onOpenChange={onOpenChange}>
        <DialogContent className="max-w-[95vw] sm:max-w-xl h-[90vh] max-h-[90vh] flex flex-col p-0 gap-0 overflow-hidden data-[state=open]:animate-in data-[state=open]:fade-in-0 data-[state=open]:zoom-in-95">
          <DialogHeader className="p-4 sm:p-6 pb-2 sm:pb-4 flex-shrink-0">
            <div className="flex justify-between items-start">
              <div>
                <DialogTitle>{nonEmployee ? 'Edytuj dane mieszkańca (NZ)' : 'Dodaj nowego mieszkańca (NZ)'}</DialogTitle>
                <DialogDescription>
                  Wypełnij poniższe pola, aby {nonEmployee ? 'zaktualizować' : 'dodać'} mieszkańca.
                </DialogDescription>
              </div>
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  onClick={() => setIsAddressPreviewOpen(true)}
                  type="button"
                  className="h-8 text-xs sm:text-sm px-3"
                >
                  <Eye className="mr-2 h-3 w-3" />
                  Podgląd miejsc
                </Button>
              </div>
            </div>
          </DialogHeader>
          <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="flex flex-col flex-1 overflow-hidden">
              <ScrollArea className="flex-1 mt-4">
                <div className="space-y-4 px-4 sm:px-6 pb-4">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="lastName"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Nazwisko</FormLabel>
                          <FormControl><Input placeholder="Nowak" {...field} /></FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="firstName"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Imię</FormLabel>
                          <FormControl><Input placeholder="Anna" {...field} /></FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <FormField
                    control={form.control}
                    name="coordinatorId"
                    render={({ field }) => (
                      <FormItem className="flex flex-col">
                        <FormLabel>Koordynator</FormLabel>
                        <FormControl>
                          <Combobox
                            options={coordinatorOptions}
                            value={field.value}
                            onChange={handleCoordinatorChange}
                            placeholder="Wybierz koordynatora"
                            searchPlaceholder="Szukaj koordynatora..."
                          />
                        </FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="nationality"
                      render={({ field }) => (
                        <FormItem className="flex flex-col">
                          <FormLabel>Narodowość</FormLabel>
                          <FormControl>
                            <Combobox
                              options={nationalityOptions}
                              value={field.value || ''}
                              onChange={field.onChange}
                              placeholder="Wybierz narodowość"
                              searchPlaceholder="Szukaj narodowości..."
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="gender"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Płeć</FormLabel>
                          <Select onValueChange={field.onChange} value={field.value || ''}>
                            <FormControl><SelectTrigger><SelectValue placeholder="Wybierz płeć" /></SelectTrigger></FormControl>
                            <SelectContent>
                              {genderOptions.filter(Boolean).map(g => <SelectItem key={g} value={g}>{g}</SelectItem>)}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>


                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="locality"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Miejscowość</FormLabel>
                          <Select onValueChange={handleLocalityChange} value={field.value || ''}>
                            <FormControl><SelectTrigger><SelectValue placeholder="Wybierz miejscowość" /></SelectTrigger></FormControl>
                            <SelectContent>
                              {availableLocalities.filter(Boolean).map(l => <SelectItem key={l} value={l}>{l}</SelectItem>)}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="address"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Adres</FormLabel>
                          <Select onValueChange={handleAddressChange} value={field.value || ''} disabled={!selectedLocality}>
                            <FormControl><SelectTrigger><SelectValue placeholder={!selectedLocality ? "Najpierw wybierz miejscowość" : "Wybierz adres"} /></SelectTrigger></FormControl>
                            <SelectContent>
                              {availableAddresses.filter(a => a.name).map(a => (
                                <SelectItem key={a.id} value={a.name} disabled={!a.isActive}>
                                  {a.name} {!a.isActive ? '(Niedostępny)' : ''}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="roomNumber"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Pokój</FormLabel>
                          <Select onValueChange={field.onChange} value={field.value || ''} disabled={!selectedAddress}>
                            <FormControl><SelectTrigger><SelectValue placeholder={!selectedAddress ? "Najpierw wybierz adres" : "Wybierz pokój"} /></SelectTrigger></FormControl>
                            <SelectContent>
                              {availableRoomsWithCapacity.filter(r => r.name).map(r => (
                                <SelectItem key={r.id} value={r.name} disabled={!r.isActive || r.isLocked}>
                                  {r.name} {r.isActive ? (r.isLocked ? '(Zablokowany)' : `(${r.available} wolnych z ${r.capacity})`) : '(Niedostępny)'}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="paymentType"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Rodzaj płatności NZ</FormLabel>
                          <Select onValueChange={field.onChange} value={field.value || ''}>
                            <FormControl><SelectTrigger><SelectValue placeholder="Wybierz rodzaj płatności" /></SelectTrigger></FormControl>
                            <SelectContent>
                              {paymentTypesNZOptions.map(p => <SelectItem key={p.value} value={p.value}>{p.label}</SelectItem>)}
                            </SelectContent>
                          </Select>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="paymentAmount"
                      render={({ field }) => (
                        <FormItem>
                          <FormLabel>Kwota</FormLabel>
                          <FormControl><Input type="number" step="0.01" {...field} onChange={e => field.onChange(e.target.value === '' ? null : parseFloat(e.target.value))} value={field.value ?? ''} placeholder="PLN" /></FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <FormField
                      control={form.control}
                      name="checkInDate"
                      render={({ field }) => (
                        <FormItem className="flex flex-col">
                          <FormLabel>Data zameldowania</FormLabel>
                          <FormControl>
                            <DateInput
                              value={field.value}
                              onChange={field.onChange}
                            />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="checkOutDate"
                      render={({ field }) => (
                        <FormItem className="flex flex-col">
                          <FormLabel>Data wymeldowania</FormLabel>
                          <FormControl>
                            <DateInput value={field.value} onChange={d => field.onChange(d)} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                    <FormField
                      control={form.control}
                      name="departureReportDate"
                      render={({ field }) => (
                        <FormItem className="flex flex-col">
                          <FormLabel>Data zgłoszenia wyjazdu</FormLabel>
                          <FormControl>
                            <DateInput value={field.value} onChange={d => field.onChange(d)} />
                          </FormControl>
                          <FormMessage />
                        </FormItem>
                      )}
                    />
                  </div>

                  <FormField
                    control={form.control}
                    name="comments"
                    render={({ field }) => (
                      <FormItem>
                        <FormLabel>Komentarze</FormLabel>
                        <FormControl><Input placeholder="Dodatkowe informacje..." {...field} /></FormControl>
                        <FormMessage />
                      </FormItem>
                    )}
                  />
                </div>
              </ScrollArea>
              <div className="p-4 sm:p-6 pt-4 flex-shrink-0 flex flex-row items-center justify-between gap-3 bg-background border-t mt-auto">
                <div className="flex justify-start">
                  {nonEmployee && nonEmployee.status === 'active' && (
                    <Button type="button" variant="destructive" onClick={handleDismissClick} className="h-8 text-xs sm:text-sm px-3 sm:px-4">
                      Zwolnij
                    </Button>
                  )}
                </div>
                <div className="flex flex-row gap-2">
                  <Button type="button" variant="outline" onClick={() => onOpenChange(false)} className="h-8 text-xs sm:text-sm px-3 sm:px-4">
                    Anuluj
                  </Button>
                  <Button type="submit" disabled={form.formState.isSubmitting} className="h-8 text-xs sm:text-sm px-3 sm:px-4">
                    {form.formState.isSubmitting && <Loader2 className="mr-2 h-3 w-3 animate-spin" />}
                    Zapisz
                  </Button>
                </div>
              </div>
            </form>
          </Form>
        </DialogContent>
      </Dialog>

      <AddressPreviewDialog
        isOpen={isAddressPreviewOpen}
        onOpenChange={setIsAddressPreviewOpen}
        settings={settings}
        allEmployees={allEmployees}
        allNonEmployees={allNonEmployees}
        coordinatorId={selectedCoordinatorId}
        onApplySelection={(locality, address, roomNumber) => {
          form.setValue('locality', locality);
          form.setValue('address', address);
          form.setValue('roomNumber', roomNumber);
          toast({
            title: "Wybór zastosowany",
            description: `${address}, pokój ${roomNumber} został wybrany.`
          });
        }}
      />
    </>
  );
}

"use client";

import React, { useMemo, useState } from 'react';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogFooter,
} from '@/components/ui/dialog';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Table, TableBody, TableCell, TableHeader, TableRow } from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import type { Settings, Employee, NonEmployee } from '@/types';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Label } from '@/components/ui/label';
import { cn } from '@/lib/utils';
import { isRoomActive, isOwnAddressEntry } from '@/lib/address-filters';
import { FilterableHeader } from '@/components/ui/filterable-header';

type AddressOccupancy = {
  locality: string;
  address: string;
  roomName: string;
  capacity: number;
  occupied: number;
  available: number;
  isActive: boolean;
};

interface AddressPreviewDialogProps {
  isOpen: boolean;
  onOpenChange: (open: boolean) => void;
  settings: Settings;
  allEmployees: Employee[] | null;
  allNonEmployees: NonEmployee[] | null;
  coordinatorId?: string;
  onApplySelection?: (locality: string, address: string, roomNumber: string) => void;
}

export function AddressPreviewDialog({
  isOpen,
  onOpenChange,
  settings,
  allEmployees,
  allNonEmployees,
  coordinatorId,
  onApplySelection,
}: AddressPreviewDialogProps) {

  const [selectedLocality, setSelectedLocality] = useState<string>('');
  const [selectedAddress, setSelectedAddress] = useState<string>('');
  const [selectedRoom, setSelectedRoom] = useState<string>('');
  const [expandedAddress, setExpandedAddress] = useState<string | null>(null);
  const [sortConfig, setSortConfig] = useState<{key: keyof AddressOccupancy | null, direction: 'asc' | 'desc'}>({ key: null, direction: 'asc' });

  const ALL_LOCALITIES = '__all__';

  const handleSort = (key: string) => {
    setSortConfig(prev => ({
      key: key as keyof AddressOccupancy,
      direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const addressOccupancy = useMemo<AddressOccupancy[]>(() => {
    if (!allEmployees || !allNonEmployees) return [];

    const activeResidents = [
      ...allEmployees.filter(e => e.status === 'active'),
      ...allNonEmployees.filter(ne => ne.status === 'active'),
    ];

    const occupancyMap = new Map<string, number>();
    activeResidents.forEach(resident => {
      if (resident.address && resident.roomNumber) {
        const key = `${resident.address}|${resident.roomNumber}`;
        occupancyMap.set(key, (occupancyMap.get(key) || 0) + 1);
      }
    });

    const result: AddressOccupancy[] = [];

    const filteredAddresses = coordinatorId
      ? settings.addresses.filter(addr => addr.coordinatorIds.includes(coordinatorId))
      : settings.addresses;

    filteredAddresses.forEach(address => {
      // Skip addresses that are "Własne mieszkanie ..."
      if (isOwnAddressEntry(address.name)) return;

      // Skip blocked/inactive addresses entirely
      if (!address.isActive) return;

      address.rooms.forEach(room => {
        // Check if room is active using the centralized filter logic
        const roomActive = isRoomActive(room, address);

        // Skip blocked/inactive rooms entirely
        if (!roomActive) return;

        const key = `${address.name}|${room.name}`;
        const occupied = occupancyMap.get(key) || 0;
        const available = Math.max(0, room.capacity - occupied);


        result.push({
          locality: address.locality,
          address: address.name,
          roomName: room.name,
          capacity: room.capacity,
          occupied,
          available,
          isActive: roomActive,
        });
      });
    });

    return result.sort((a, b) => {
      if (a.locality !== b.locality) return a.locality.localeCompare(b.locality);
      if (a.address !== b.address) return a.address.localeCompare(b.address);
      return a.roomName.localeCompare(b.roomName);
    });
  }, [settings, allEmployees, allNonEmployees, coordinatorId]);

  // Get unique localities
  const localities = useMemo(() => {
    const localitySet = new Set(addressOccupancy.map(item => item.locality));
    return Array.from(localitySet).sort();
  }, [addressOccupancy]);

  // Get addresses for selected locality
  const availableAddresses = useMemo(() => {
    if (!selectedLocality || selectedLocality === ALL_LOCALITIES) return [];
    const addressSet = new Set(
      addressOccupancy
        .filter(item => item.locality === selectedLocality && item.isActive)
        .map(item => item.address)
    );
    return Array.from(addressSet).sort();
  }, [addressOccupancy, selectedLocality, ALL_LOCALITIES]);

  // Address-level summary for selected locality (to show address blocks)
  const selectedLocalityAddresses = useMemo(() => {
    if (!selectedLocality || selectedLocality === ALL_LOCALITIES) return [];
    const addressMap = new Map<string, { total: number; occupied: number; available: number }>();
    addressOccupancy
      .filter(item => item.locality === selectedLocality && item.isActive)
      .forEach(item => {
        const current = addressMap.get(item.address) || { total: 0, occupied: 0, available: 0 };
        addressMap.set(item.address, {
          total: current.total + item.capacity,
          occupied: current.occupied + item.occupied,
          available: current.available + Math.max(0, item.capacity - item.occupied),
        });
      });
    return Array.from(addressMap.entries())
      .map(([address, data]) => ({ address, ...data }))
      .sort((a, b) => a.address.localeCompare(b.address));
  }, [addressOccupancy, selectedLocality, ALL_LOCALITIES]);

  // Get rooms for selected address
  const availableRooms = useMemo(() => {
    if (!selectedAddress || selectedLocality === ALL_LOCALITIES) return [];
    return addressOccupancy
      .filter(item =>
        item.locality === selectedLocality &&
        item.address === selectedAddress &&
        item.isActive
      )
      .sort((a, b) => a.roomName.localeCompare(b.roomName));
  }, [addressOccupancy, selectedLocality, selectedAddress, ALL_LOCALITIES]);

  // Get occupancy info for selected items
  const selectedRoomInfo = useMemo(() => {
    if (!selectedRoom) return null;
    return addressOccupancy.find(item =>
      item.locality === selectedLocality &&
      item.address === selectedAddress &&
      item.roomName === selectedRoom
    );
  }, [addressOccupancy, selectedLocality, selectedAddress, selectedRoom]);

  // Group by locality for table view
  const groupedByLocality = useMemo(() => {
    const groups = new Map<string, AddressOccupancy[]>();
    addressOccupancy.forEach(item => {
      const items = groups.get(item.locality) || [];
      items.push(item);
      groups.set(item.locality, items);
    });

    // Sort items within each locality
    const entries = Array.from(groups.entries()).map(([loc, items]) => {
       const sortedItems = [...items];
       if (sortConfig.key) {
         sortedItems.sort((a, b) => {
           let valA = a[sortConfig.key as keyof AddressOccupancy];
           let valB = b[sortConfig.key as keyof AddressOccupancy];

           if (sortConfig.key === 'isActive') {
              valA = a.isActive ? 1 : 0;
              valB = b.isActive ? 1 : 0;
           }

           if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
           if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
           return 0;
         });
       }
       return [loc, sortedItems] as [string, AddressOccupancy[]];
    });

    return entries.sort((a, b) => a[0].localeCompare(b[0]));
  }, [addressOccupancy, sortConfig]);

  const localitySummary = useMemo(() => {
    const summary = new Map<string, { total: number; occupied: number; available: number }>();

    // Only include active (non-blocked) rooms in the summary
    addressOccupancy.forEach(item => {
      if (!item.isActive) return;

      const current = summary.get(item.locality) || { total: 0, occupied: 0, available: 0 };

      // Calculate true available for this specific item (never negative)
      const trueAvailable = Math.max(0, item.capacity - item.occupied);

      summary.set(item.locality, {
        total: current.total + item.capacity,
        occupied: current.occupied + item.occupied,
        available: current.available + trueAvailable,
      });
    });

    return Array.from(summary.entries()).map(([locality, data]) => ({
      locality,
      ...data,
    })).sort((a, b) => a.locality.localeCompare(b.locality));
  }, [addressOccupancy]);

  const getAvailabilityBadge = (available: number, _capacity: number) => {
    if (available === 0) {
      return <Badge variant="destructive">Pełny</Badge>;
    }
    return <Badge className="bg-green-500 hover:bg-green-600">Wolne</Badge>;
  };

  const handleApply = () => {
    if (selectedLocality && selectedLocality !== ALL_LOCALITIES && selectedAddress && selectedRoom && onApplySelection) {
      onApplySelection(selectedLocality, selectedAddress, selectedRoom);
      onOpenChange(false);
      // Reset selections
      setSelectedLocality('');
      setSelectedAddress('');
      setSelectedRoom('');
    }
  };

  const handleClose = () => {
    onOpenChange(false);
    // Reset selections on close
    setSelectedLocality('');
    setSelectedAddress('');
    setSelectedRoom('');
  };

  return (
    <Dialog open={isOpen} onOpenChange={handleClose}>
      <DialogContent className="max-w-[96vw] sm:max-w-3xl lg:max-w-5xl max-h-[92vh] p-3 sm:p-6 gap-3 sm:gap-4">
        <DialogHeader>
          <DialogTitle className="text-base sm:text-lg">Podgląd i wybór dostępności miejsc</DialogTitle>
          <DialogDescription className="text-xs sm:text-sm">
            Wybierz miejscowość, aby zobaczyć dostępność adresów
          </DialogDescription>
        </DialogHeader>

        <ScrollArea className="h-[52vh] sm:h-[60vh] lg:h-[70vh]">
          <div className="pr-3 space-y-4 sm:space-y-6">
            {/* Interactive Selection Section */}
            <div className="p-3 sm:p-4 border rounded-lg bg-muted/50">
              <h3 className="text-sm font-semibold mb-3 sm:mb-4">Wybierz zakwaterowanie</h3>
              <div className="space-y-2 max-w-xs">
                <Label htmlFor="locality-select">Miejscowość</Label>
                <Select value={selectedLocality} onValueChange={(value) => {
                  setSelectedLocality(value);
                  setSelectedAddress('');
                  setSelectedRoom('');
                  setExpandedAddress(null);
                }}>
                  <SelectTrigger id="locality-select">
                    <SelectValue placeholder="Wybierz miejscowość" />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value={ALL_LOCALITIES}>Wszystkie miejscowości</SelectItem>
                    {localities.map(locality => (
                      <SelectItem key={locality} value={locality}>
                        {locality}
                      </SelectItem>
                    ))}
                  </SelectContent>
                </Select>
              </div>
            </div>

            {/* Summary Cards — gdy wybrane "Wszystkie" lub nic */}
            {(!selectedLocality || selectedLocality === ALL_LOCALITIES) && localitySummary.length > 0 && (
              <div>
                <h3 className="text-sm font-semibold mb-3">Podsumowanie według miejscowości</h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 sm:gap-3">
                  {localitySummary.map((summary) => (
                    <Card key={summary.locality}>
                      <CardHeader className="p-3 sm:pb-3">
                        <CardTitle className="text-sm font-medium">{summary.locality}</CardTitle>
                      </CardHeader>
                      <CardContent className="p-3 pt-0 sm:p-6 sm:pt-0">
                        <div className="space-y-1 text-xs sm:text-sm">
                          <div className="flex justify-between">
                            <span className="text-muted-foreground">Całkowita pojemność:</span>
                            <span className="font-medium">{summary.total}</span>
                          </div>
                          <div className="flex justify-between">
                            <span className="text-muted-foreground">Zajęte:</span>
                            <span className="font-medium text-orange-600">{summary.occupied}</span>
                          </div>
                          <div className="flex justify-between">
                            <span className="text-muted-foreground">Dostępne:</span>
                            <span className="font-medium text-green-600">{summary.available}</span>
                          </div>
                        </div>
                      </CardContent>
                    </Card>
                  ))}
                </div>
              </div>
            )}

            {/* Address blocks — gdy wybrana konkretna miejscowość */}
            {selectedLocalityAddresses.length > 0 && (
              <div>
                <h3 className="text-sm font-semibold mb-3">
                  Adresy w miejscowości: <span className="text-primary">{selectedLocality}</span>
                </h3>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-2 sm:gap-3">
                  {selectedLocalityAddresses.map((addr) => {
                    const isExpanded = expandedAddress === addr.address;
                    return (
                      <Card
                        key={addr.address}
                        className={cn('cursor-pointer transition-all hover:shadow-md', addr.available === 0 && 'opacity-60', isExpanded && 'ring-2 ring-primary')}
                        onClick={() => setExpandedAddress(isExpanded ? null : addr.address)}
                      >
                        <CardHeader className="p-3 pb-2">
                          <CardTitle className="text-xs font-medium leading-tight">{addr.address}</CardTitle>
                        </CardHeader>
                        <CardContent className="p-3 pt-0">
                          <div className="space-y-1 text-xs">
                            <div className="flex justify-between">
                              <span className="text-muted-foreground">Całkowita pojemność:</span>
                              <span className="font-medium">{addr.total}</span>
                            </div>
                            <div className="flex justify-between">
                              <span className="text-muted-foreground">Zajęte:</span>
                              <span className="font-medium text-orange-600">{addr.occupied}</span>
                            </div>
                            <div className="flex justify-between">
                              <span className="text-muted-foreground">Dostępne:</span>
                              <span className="font-medium text-green-600">{addr.available}</span>
                            </div>
                          </div>
                          <div className="mt-2">
                            {getAvailabilityBadge(addr.available, addr.total)}
                          </div>
                        </CardContent>
                      </Card>
                    );
                  })}
                </div>

                {/* Panel pokojów — pełna szerokość pod kartami */}
                {expandedAddress && (() => {
                  const rooms = addressOccupancy
                    .filter(item => item.locality === selectedLocality && item.address === expandedAddress && item.isActive)
                    .sort((a, b) => b.available - a.available || a.roomName.localeCompare(b.roomName));
                  return (
                    <div className="mt-3 border rounded-lg overflow-hidden">
                      <div className="bg-muted/50 px-4 py-2 text-sm font-semibold">
                        Pokoje — {expandedAddress}
                      </div>
                      <table className="w-full text-xs">
                        <thead>
                          <tr className="bg-muted/30 border-b">
                            <th className="text-left px-4 py-2 font-medium text-muted-foreground">Pokój</th>
                            <th className="text-center px-4 py-2 font-medium text-muted-foreground">Pojemność</th>
                            <th className="text-center px-4 py-2 font-medium text-orange-600">Zajęte</th>
                            <th className="text-center px-4 py-2 font-medium text-green-600">Wolne</th>
                            <th className="text-center px-4 py-2 font-medium text-muted-foreground">Status</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y">
                          {rooms.map((room) => (
                            <tr key={room.roomName}>
                              <td className="px-4 py-2 font-medium">Pokój {room.roomName}</td>
                              <td className="px-4 py-2 text-center">{room.capacity}</td>
                              <td className="px-4 py-2 text-center font-medium text-orange-600">{room.occupied}</td>
                              <td className="px-4 py-2 text-center font-medium text-green-600">{room.available}</td>
                              <td className="px-4 py-2 text-center">
                                <div className="flex justify-center">
                                  {getAvailabilityBadge(room.available, room.capacity)}
                                </div>
                              </td>
                            </tr>
                          ))}
                        </tbody>
                      </table>
                    </div>
                  );
                })()}
              </div>
            )}

            {addressOccupancy.length === 0 && (
              <div className="text-center py-8 text-muted-foreground">
                Brak danych o adresach
              </div>
            )}
          </div>
        </ScrollArea>

        <DialogFooter className="gap-2 flex-col sm:flex-row">
          <Button
            variant="outline"
            onClick={handleClose}
            className="w-full sm:w-auto min-h-[44px] order-2 sm:order-1"
          >
            Anuluj
          </Button>
          {onApplySelection && (
            <Button
              onClick={handleApply}
              disabled={!selectedLocality || selectedLocality === ALL_LOCALITIES || !selectedAddress || !selectedRoom}
              className="w-full sm:w-auto min-h-[44px] order-1 sm:order-2"
            >
              Zastosuj wybór
            </Button>
          )}
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

"use client";

import React, { useState, useMemo, useTransition } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import {
    ClipboardCheck, Search, CheckCircle2,
    AlertCircle, Clock, ChevronRight, Building2,
    ShieldCheck, Wrench, ChevronDown, Bed,
