const FIELD_LABELS: Record<string, string> = {
    firstName: "Imię",
    lastName: "Nazwisko",
    coordinatorId: "Koordynator",
    nationality: "Narodowość",
    gender: "Płeć",
    address: "Adres",
    ownAddress: "Adres własny",
    roomNumber: "Pokój",
    zaklad: "Zakład",
    checkInDate: "Data zameldowania",
    checkOutDate: "Data wymeldowania",
